package com.bmstu.iu3.automanagement

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.layout.*
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.Build
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.compose.ui.res.colorResource
import androidx.compose.ui.text.font.Font
import androidx.compose.ui.text.font.FontFamily
import androidx.compose.ui.unit.dp
import androidx.lifecycle.viewmodel.compose.viewModel
import androidx.navigation.compose.rememberNavController
import com.bmstu.iu3.automanagement.R.font.game_font
import com.bmstu.iu3.automanagement.R.font.press_start2p
import com.bmstu.iu3.automanagement.models.MainViewModel
import com.bmstu.iu3.automanagement.ui.navigation.SetupNavGraph
import com.bmstu.iu3.automanagement.ui.theme.AutoManagementTheme
import com.bmstu.iu3.automanagement.utils.DevMenuDialog

class MainActivity : ComponentActivity() {
    @OptIn(ExperimentalMaterial3Api::class)
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            val mainViewModel: MainViewModel = viewModel()
            val budgetText = mainViewModel.getBudgetDisplay()

            var showDevMenu by remember { mutableStateOf(false) }

            AutoManagementTheme {
                Surface(
                    modifier = Modifier.fillMaxSize(),
                    color = colorResource(id = R.color.black)
                ) {
                    val navController = rememberNavController()
                    Scaffold(
                        modifier = Modifier.fillMaxSize(),
                        containerColor = MaterialTheme.colorScheme.surface,
                        topBar = {
                            TopAppBar(
                                title = { Text("Auto Management", fontFamily = FontFamily(Font(game_font))) },
                                actions = {
                                    IconButton(onClick = { showDevMenu = true }) {
                                        Icon(
                                            Icons.Default.Build, 
                                            contentDescription = "Dev Menu", 
                                            tint = MaterialTheme.colorScheme.secondary
                                        )
                                    }

                                    Text(
                                        text = budgetText,
                                        modifier = Modifier.padding(end = 16.dp),
                                        style = MaterialTheme.typography.titleMedium,
                                        color = MaterialTheme.colorScheme.primary,
                                        fontFamily = FontFamily(Font(press_start2p))
                                    )
                                },
                                colors = TopAppBarDefaults.topAppBarColors(
                                    containerColor = MaterialTheme.colorScheme.background,
                                    titleContentColor = MaterialTheme.colorScheme.onBackground
                                )
                            )
                        }
                    ) { innerPadding ->
                        Box(modifier = Modifier.padding(innerPadding)) {
                            SetupNavGraph(
                                navController = navController,
                                onExit = { finish() }
                            )
                        }
                    }

                    if (showDevMenu) {
                        DevMenuDialog(onDismiss = { showDevMenu = false })
                    }
                }
            }
        }
    }
}

package com.bmstu.iu3.automanagement

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.layout.*
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.Build
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.compose.ui.res.colorResource
import androidx.compose.ui.text.font.Font
import androidx.compose.ui.text.font.FontFamily
import androidx.compose.ui.unit.dp
import androidx.lifecycle.viewmodel.compose.viewModel
import androidx.navigation.compose.rememberNavController
import com.bmstu.iu3.automanagement.R.font.game_font
import com.bmstu.iu3.automanagement.R.font.press_start2p
import com.bmstu.iu3.automanagement.data.GameState
import com.bmstu.iu3.automanagement.data.GameSaveManager
import com.bmstu.iu3.automanagement.models.MainViewModel
import com.bmstu.iu3.automanagement.ui.navigation.SetupNavGraph
import com.bmstu.iu3.automanagement.ui.theme.AutoManagementTheme
import com.bmstu.iu3.automanagement.utils.DevMenuDialog

class MainActivity : ComponentActivity() {
    @OptIn(ExperimentalMaterial3Api::class)
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            val mainViewModel: MainViewModel = viewModel()
            val budgetText = mainViewModel.getBudgetDisplay()
            val saveManager = GameSaveManager(this@MainActivity)

            var showDevMenu by remember { mutableStateOf(false) }

            AutoManagementTheme {
                Surface(
                    modifier = Modifier.fillMaxSize(),
                    color = colorResource(id = R.color.black)
                ) {
                    val navController = rememberNavController()
                    Scaffold(
                        modifier = Modifier.fillMaxSize(),
                        containerColor = MaterialTheme.colorScheme.surface,
                        topBar = {
                            TopAppBar(
                                title = {
                                    Column {
                                        Text("Auto Management", fontFamily = FontFamily(Font(game_font)))
                                        if (GameState.getCurrentPlayer().isNotEmpty()) {
                                            Text(
                                                "Player: ${GameState.getCurrentPlayer()}",
                                                style = MaterialTheme.typography.labelSmall
                                            )
                                        }
                                    }
                                },
                                actions = {
                                    IconButton(onClick = { showDevMenu = true }) {
                                        Icon(
                                            Icons.Default.Build, 
                                            contentDescription = "Dev Menu", 
                                            tint = MaterialTheme.colorScheme.secondary
                                        )
                                    }

                                    Text(
                                        text = budgetText,
                                        modifier = Modifier.padding(end = 16.dp),
                                        style = MaterialTheme.typography.titleMedium,
                                        color = MaterialTheme.colorScheme.primary,
                                        fontFamily = FontFamily(Font(press_start2p))
                                    )
                                },
                                colors = TopAppBarDefaults.topAppBarColors(
                                    containerColor = MaterialTheme.colorScheme.background,
                                    titleContentColor = MaterialTheme.colorScheme.onBackground
                                )
                            )
                        }
                    ) { innerPadding ->
                        Box(modifier = Modifier.padding(innerPadding)) {
                            SetupNavGraph(
                                navController = navController,
                                onExit = { finish() },
                                saveManager = saveManager
                            )
                        }
                    }

                    if (showDevMenu) {
                        DevMenuDialog(onDismiss = { showDevMenu = false })
                    }
                }
            }
        }
    }
}

package com.bmstu.iu3.automanagement.data

import android.content.Context
import android.content.SharedPreferences
import com.google.gson.Gson
import com.google.gson.GsonBuilder
import com.bmstu.iu3.automanagement.models.*

class GameSaveManager(private val context: Context) {
    private val sharedPreferences: SharedPreferences =
        context.getSharedPreferences("game_saves", Context.MODE_PRIVATE)

    private val gson: Gson = GsonBuilder()
        .setPrettyPrinting()
        .create()

    fun saveGame(playerName: String) {
        try {
            val saveData = GameStateSaveData(
                playerName = playerName,
                budget = GameState.getBudgetObject().getAmount(),
                ownedComponents = GameState.getOwnedComponents().map { convertComponent(it) },
                assembledCars = GameState.getAssembledCars().map { convertCar(it) },
                hiredEngineers = GameState.getHiredEngineers().map { convertWorker(it, "Engineer") },
                hiredPilots = GameState.getHiredPilots().map { convertWorker(it, "Pilot") },
                jailedPilots = GameState.getJailedPilots().map { convertWorker(it, "Pilot") },
                raceHistory = GameState.getRaceHistory().map { raceList ->
                    raceList.map { race ->
                        RaceResultSaveData(
                            pilotName = race.getTeamName(),
                            position = race.getPosition(),
                            time = race.getTime(),
                            incidents = race.getIncident()?.getReason() ?: ""
                        )
                    }
                },
                timestamp = System.currentTimeMillis()
            )

            val json = gson.toJson(saveData)
            sharedPreferences.edit().apply {
                putString("save_$playerName", json)
                putString("current_player", playerName)
                putStringSet(
                    "all_players",
                    (getAllPlayers() + playerName).toSet()
                )
            }.apply()
        } catch (e: Exception) {
            e.printStackTrace()
        }
    }

    fun loadGame(playerName: String): Boolean {
        return try {
            if (!gameExists(playerName)) return false

            val json = sharedPreferences.getString("save_$playerName", null) ?: return false
            val saveData = gson.fromJson(json, GameStateSaveData::class.java)

            GameState.setCurrentPlayer(playerName)
            GameState.setBudget(saveData.budget)
            GameState.clearInventory()

            saveData.ownedComponents.forEach { data ->
                val component = createComponentFromSaveData(data)
                GameState.addComponent(component)
            }

            saveData.assembledCars.forEach { data ->
                val car = createCarFromSaveData(data)
                GameState.addCar(car)
            }

            saveData.hiredEngineers.forEach { data ->
                val engineer = Engineer().apply {
                    setName(data.name)
                    setSkill(data.skill)
                    setSalary(data.salary)
                }
                GameState.addEngineerDirectly(engineer)
            }

            saveData.hiredPilots.forEach { data ->
                val pilot = createPilotFromSaveData(data)
                GameState.addPilotDirectly(pilot)
            }

            saveData.jailedPilots.forEach { data ->
                val pilot = createPilotFromSaveData(data)
                GameState.addJailedPilotDirectly(pilot)
            }

            sharedPreferences.edit().putString("current_player", playerName).apply()
            return true
        } catch (e: Exception) {
            e.printStackTrace()
            return false
        }
    }

    fun createNewGame(playerName: String): Boolean {
        return try {
            GameState.setCurrentPlayer(playerName)
            GameState.setBudget(10000.0)
            GameState.clearInventory()

            saveGame(playerName)
            true
        } catch (e: Exception) {
            e.printStackTrace()
            false
        }
    }

    fun gameExists(playerName: String): Boolean {
        return sharedPreferences.contains("save_$playerName")
    }

    fun getAllPlayers(): Set<String> {
        return sharedPreferences.getStringSet("all_players", emptySet()) ?: emptySet()
    }

    fun getCurrentPlayer(): String? {
        val current = sharedPreferences.getString("current_player", null)
        return if (current.isNullOrEmpty()) null else current
    }

    fun deleteGame(playerName: String): Boolean {
        return try {
            sharedPreferences.edit().apply {
                remove("save_$playerName")
                val allPlayers = getAllPlayers().toMutableSet()
                allPlayers.remove(playerName)
                putStringSet("all_players", allPlayers)
                if (getCurrentPlayer() == playerName) {
                    putString("current_player", "")
                }
            }.apply()
            true
        } catch (e: Exception) {
            false
        }
    }


    private fun convertComponent(component: Component): ComponentSaveData {
        return ComponentSaveData(
            id = component.getId(),
            name = component.getName(),
            price = component.getPrice(),
            performance = component.getPerformance(),
            wear = component.getWear(),
            isDestroyed = component.isDestroyed(),
            type = when (component) {
                is Engine -> "Engine"
                is Gearbox -> "Gearbox"
                is Chassis -> "Chassis"
                is Suspension -> "Suspension"
                is Aerodynamics -> "Aerodynamics"
                is Tyres -> "Tyres"
                else -> "Unknown"
            },
            power = if (component is Engine) component.getPower() else null,
            weight = if (component is Engine) component.getWeight() else null,
            gears = if (component is Gearbox) component.getGears() else null
        )
    }

    private fun convertCar(car: Car): CarSaveData {
        return CarSaveData(
            name = car.getName(),
            performance = car.getPerformance(),
            engine = car.getEngine()?.let { convertComponent(it) },
            gearbox = car.getGearbox()?.let { convertComponent(it) },
            chassis = car.getChassis()?.let { convertComponent(it) },
            suspension = car.getSuspension()?.let { convertComponent(it) },
            aerodynamics = car.getAerodynamics()?.let { convertComponent(it) },
            tyres = car.getTyres()?.let { convertComponent(it) }
        )
    }

    private fun convertWorker(worker: Worker, type: String): WorkerSaveData {
        return WorkerSaveData(
            name = worker.getName(),
            skill = worker.getSkill(),
            salary = worker.getSalary(),
            type = type,
            fineAmount = if (worker is Pilot) worker.getFineAmount() else null,
            fineDeadline = if (worker is Pilot) worker.getFineDeadline() else null,
            jailSentence = if (worker is Pilot) worker.getJailSentence() else null
        )
    }

    private fun createComponentFromSaveData(data: ComponentSaveData): Component {
        return when (data.type) {
            "Engine" -> Engine().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
                data.power?.let { setPower(it) }
                data.weight?.let { setWeight(it) }
            }
            "Gearbox" -> Gearbox().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
                data.gears?.let { setGears(it) }
            }
            "Chassis" -> Chassis().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
            }
            "Suspension" -> Suspension().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
            }
            "Aerodynamics" -> Aerodynamics().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
            }
            "Tyres" -> Tyres().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
            }
            else -> Engine() // Fallback
        }
    }

    private fun createCarFromSaveData(data: CarSaveData): Car {
        return Car().apply {
            setName(data.name)
            setPerformance(data.performance)
            data.engine?.let { setEngine(createComponentFromSaveData(it) as Engine) }
            data.gearbox?.let { setGearbox(createComponentFromSaveData(it) as Gearbox) }
            data.chassis?.let { setChassis(createComponentFromSaveData(it) as Chassis) }
            data.suspension?.let { setSuspension(createComponentFromSaveData(it) as Suspension) }
            data.aerodynamics?.let { setAerodynamics(createComponentFromSaveData(it) as Aerodynamics) }
            data.tyres?.let { setTyres(createComponentFromSaveData(it) as Tyres) }
        }
    }

    private fun createPilotFromSaveData(data: WorkerSaveData): Pilot {
        return Pilot().apply {
            setName(data.name)
            setSkill(data.skill)
            setSalary(data.salary)
            data.fineAmount?.let { setFineAmount(it) }
            data.fineDeadline?.let { setFineDeadline(it) }
            data.jailSentence?.let { setJailSentence(it) }
        }
    }
}

package com.bmstu.iu3.automanagement.data

import android.content.Context
import android.content.SharedPreferences
import com.google.gson.Gson
import com.google.gson.GsonBuilder
import com.bmstu.iu3.automanagement.models.*

class GameSaveManager(private val context: Context) {
    private val sharedPreferences: SharedPreferences =
        context.getSharedPreferences("game_saves", Context.MODE_PRIVATE)

    private val gson: Gson = GsonBuilder()
        .setPrettyPrinting()
        .create()

    fun saveGame(playerName: String) {
        try {
            val saveData = GameStateSaveData(
                playerName = playerName,
                budget = GameState.getBudgetObject().getAmount(),
                ownedComponents = GameState.getOwnedComponents().map { convertComponent(it) },
                assembledCars = GameState.getAssembledCars().map { convertCar(it) },
                hiredEngineers = GameState.getHiredEngineers().map { convertWorker(it, "Engineer") },
                hiredPilots = GameState.getHiredPilots().map { convertWorker(it, "Pilot") },
                jailedPilots = GameState.getJailedPilots().map { convertWorker(it, "Pilot") },
                raceHistory = GameState.getRaceHistory().map { raceList ->
                    raceList.map { race ->
                        RaceResultSaveData(
                            pilotName = race.getTeamName(),
                            position = race.getPosition(),
                            time = race.getTime(),
                            incidents = race.getIncident()?.getReason() ?: ""
                        )
                    }
                },
                timestamp = System.currentTimeMillis()
            )

            val json = gson.toJson(saveData)
            sharedPreferences.edit().apply {
                putString("save_$playerName", json)
                putString("current_player", playerName)
                putStringSet(
                    "all_players",
                    (getAllPlayers() + playerName).toSet()
                )
            }.apply()
        } catch (e: Exception) {
            e.printStackTrace()
        }
    }

    fun loadGame(playerName: String): Boolean {
        return try {
            if (!gameExists(playerName)) return false

            val json = sharedPreferences.getString("save_$playerName", null) ?: return false
            val saveData = gson.fromJson(json, GameStateSaveData::class.java)

            GameState.setCurrentPlayer(playerName)
            GameState.setBudget(saveData.budget)
            GameState.clearInventory()

            saveData.ownedComponents.forEach { data ->
                val component = createComponentFromSaveData(data)
                GameState.addComponent(component)
            }

            saveData.assembledCars.forEach { data ->
                val car = createCarFromSaveData(data)
                GameState.addCar(car)
            }

            saveData.hiredEngineers.forEach { data ->
                val engineer = Engineer().apply {
                    setName(data.name)
                    setSkill(data.skill)
                    setSalary(data.salary)
                }
                GameState.addEngineerDirectly(engineer)
            }

            saveData.hiredPilots.forEach { data ->
                val pilot = createPilotFromSaveData(data)
                GameState.addPilotDirectly(pilot)
            }

            saveData.jailedPilots.forEach { data ->
                val pilot = createPilotFromSaveData(data)
                GameState.addJailedPilotDirectly(pilot)
            }

            sharedPreferences.edit().putString("current_player", playerName).apply()
            return true
        } catch (e: Exception) {
            e.printStackTrace()
            return false
        }
    }

    fun createNewGame(playerName: String): Boolean {
        return try {
            GameState.setCurrentPlayer(playerName)
            GameState.setBudget(10000.0)
            GameState.clearInventory()

            saveGame(playerName)
            true
        } catch (e: Exception) {
            e.printStackTrace()
            false
        }
    }

    fun gameExists(playerName: String): Boolean {
        return sharedPreferences.contains("save_$playerName")
    }

    fun getAllPlayers(): Set<String> {
        return sharedPreferences.getStringSet("all_players", emptySet()) ?: emptySet()
    }

    fun getCurrentPlayer(): String? {
        val current = sharedPreferences.getString("current_player", null)
        return if (current.isNullOrEmpty()) null else current
    }

    fun deleteGame(playerName: String): Boolean {
        return try {
            sharedPreferences.edit().apply {
                remove("save_$playerName")
                val allPlayers = getAllPlayers().toMutableSet()
                allPlayers.remove(playerName)
                putStringSet("all_players", allPlayers)
                if (getCurrentPlayer() == playerName) {
                    putString("current_player", "")
                }
            }.apply()
            true
        } catch (e: Exception) {
            false
        }
    }


    private fun convertComponent(component: Component): ComponentSaveData {
        return ComponentSaveData(
            id = component.getId(),
            name = component.getName(),
            price = component.getPrice(),
            performance = component.getPerformance(),
            wear = component.getWear(),
            isDestroyed = component.isDestroyed(),
            type = when (component) {
                is Engine -> "Engine"
                is Gearbox -> "Gearbox"
                is Chassis -> "Chassis"
                is Suspension -> "Suspension"
                is Aerodynamics -> "Aerodynamics"
                is Tyres -> "Tyres"
                is MeleeWeapon -> "MeleeWeapon"
                is RangedWeapon -> "RangedWeapon"
                else -> "Unknown"
            },
            power = if (component is Engine) component.getPower() else null,
            weight = if (component is Engine) component.getWeight() else null,
            gears = if (component is Gearbox) component.getGears() else null,
            componentType = when (component) {
                is Engine -> component.getType()
                is Gearbox -> component.getType()
                is Suspension -> component.getType()
                else -> null
            },
            maxEngineWeight = if (component is Chassis) component.getMaxEngineWeight() else null,
            suspensionType = if (component is Chassis) component.getSuspensionType() else null,
            grip = if (component is Tyres) component.getGrip() else null,
            accuracy = if (component is Weapon) component.getAccuracy() else null,
            impact = if (component is MeleeWeapon) component.getImpact() else null,
            range = if (component is RangedWeapon) component.getRange() else null
        )
    }

    private fun convertCar(car: Car): CarSaveData {
        return CarSaveData(
            name = car.getName(),
            performance = car.getPerformance(),
            engine = car.getEngine()?.let { convertComponent(it) },
            gearbox = car.getGearbox()?.let { convertComponent(it) },
            chassis = car.getChassis()?.let { convertComponent(it) },
            suspension = car.getSuspension()?.let { convertComponent(it) },
            aerodynamics = car.getAerodynamics()?.let { convertComponent(it) },
            tyres = car.getTyres()?.let { convertComponent(it) },
            meleeWeapon1 = car.getMeleeWeapon1()?.let { convertComponent(it) },
            meleeWeapon2 = car.getMeleeWeapon2()?.let { convertComponent(it) },
            rangedWeapon = car.getRangedWeapon()?.let { convertComponent(it) }
        )
    }

    private fun convertWorker(worker: Worker, type: String): WorkerSaveData {
        return WorkerSaveData(
            name = worker.getName(),
            skill = worker.getSkill(),
            salary = worker.getSalary(),
            type = type,
            fineAmount = if (worker is Pilot) worker.getFineAmount() else null,
            fineDeadline = if (worker is Pilot) worker.getFineDeadline() else null,
            jailSentence = if (worker is Pilot) worker.getJailSentence() else null
        )
    }

    private fun createComponentFromSaveData(data: ComponentSaveData): Component {
        return when (data.type) {
            "Engine" -> Engine().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
                data.power?.let { setPower(it) }
                data.weight?.let { setWeight(it) }
                data.componentType?.let { setType(it) }
            }
            "Gearbox" -> Gearbox().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
                data.gears?.let { setGears(it) }
                data.componentType?.let { setType(it) }
            }
            "Chassis" -> Chassis().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
                data.maxEngineWeight?.let { setMaxEngineWeight(it) }
                data.suspensionType?.let { setSuspensionType(it) }
            }
            "Suspension" -> Suspension().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
                data.componentType?.let { setType(it) }
            }
            "Aerodynamics" -> Aerodynamics().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
            }
            "Tyres" -> Tyres().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
                data.grip?.let { setGrip(it) }
            }
            "MeleeWeapon" -> MeleeWeapon().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
                data.weight?.let { setWeight(it) }
                data.accuracy?.let { setAccuracy(it) }
                data.impact?.let { setImpact(it) }
            }
            "RangedWeapon" -> RangedWeapon().apply {
                setId(data.id)
                setName(data.name)
                setPrice(data.price)
                setPerformance(data.performance)
                setWear(data.wear)
                setDestroyed(data.isDestroyed)
                data.weight?.let { setWeight(it) }
                data.accuracy?.let { setAccuracy(it) }
                data.range?.let { setRange(it) }
            }
            else -> Engine() // Fallback
        }
    }

    private fun createCarFromSaveData(data: CarSaveData): Car {
        return Car().apply {
            setName(data.name)
            setPerformance(data.performance)
            data.engine?.let { setEngine(createComponentFromSaveData(it) as Engine) }
            data.gearbox?.let { setGearbox(createComponentFromSaveData(it) as Gearbox) }
            data.chassis?.let { setChassis(createComponentFromSaveData(it) as Chassis) }
            data.suspension?.let { setSuspension(createComponentFromSaveData(it) as Suspension) }
            data.aerodynamics?.let { setAerodynamics(createComponentFromSaveData(it) as Aerodynamics) }
            data.tyres?.let { setTyres(createComponentFromSaveData(it) as Tyres) }
            data.meleeWeapon1?.let { setMeleeWeapon1(createComponentFromSaveData(it) as MeleeWeapon) }
            data.meleeWeapon2?.let { setMeleeWeapon2(createComponentFromSaveData(it) as MeleeWeapon) }
            data.rangedWeapon?.let { setRangedWeapon(createComponentFromSaveData(it) as RangedWeapon) }
        }
    }

    private fun createPilotFromSaveData(data: WorkerSaveData): Pilot {
        return Pilot().apply {
            setName(data.name)
            setSkill(data.skill)
            setSalary(data.salary)
            data.fineAmount?.let { setFineAmount(it) }
            data.fineDeadline?.let { setFineDeadline(it) }
            data.jailSentence?.let { setJailSentence(it) }
        }
    }
}

package com.bmstu.iu3.automanagement.data

import androidx.compose.runtime.MutableState
import androidx.compose.runtime.mutableStateListOf
import androidx.compose.runtime.mutableStateOf
import com.bmstu.iu3.automanagement.models.*
import com.bmstu.iu3.automanagement.utils.MarketGenerator
import com.bmstu.iu3.automanagement.utils.OpponentGenerator

object GameState {
    private val budget: MutableState<Budget> = mutableStateOf(Budget())
    private var currentPlayer: String = ""

    private val ownedComponents = mutableStateListOf<Component>()
    private val assembledCars = mutableStateListOf<Car>()
    private val hiredEngineers = mutableStateListOf<Engineer>()
    private val hiredPilots = mutableStateListOf<Pilot>()
    private val jailedPilots = mutableStateListOf<Pilot>()
    private val opponentTeams = mutableStateListOf<OpponentTeam>()

    private val tracks = mutableStateListOf<Track>()
    private val raceHistory = mutableStateListOf<List<RaceResult>>()

    private val marketComponents = mutableStateListOf<Component>().apply {
        addAll(MarketGenerator.generateInitialMarket())
    }

    private val marketEngineers = mutableStateListOf<Engineer>().apply {
        val (engineers, _) = MarketGenerator.generateStaff()
        addAll(engineers)
    }

    private val marketPilots = mutableStateListOf<Pilot>().apply {
        val (_, pilots) = MarketGenerator.generateStaff()
        addAll(pilots)
    }

    init {
        tracks.add(Track().apply { setName("Monza"); setLength(5.79); setStraightsRatio(0.7); setCornersRatio(0.3); setElevationChange(10.0) })
        tracks.add(Track().apply { setName("Monaco"); setLength(3.33); setStraightsRatio(0.2); setCornersRatio(0.8); setElevationChange(40.0) })
        tracks.add(Track().apply { setName("Spa"); setLength(7.00); setStraightsRatio(0.5); setCornersRatio(0.5); setElevationChange(100.0) })
    }

    fun getBudgetObject() : Budget = budget.value
    fun getCurrentPlayer(): String = currentPlayer
    fun setCurrentPlayer(playerName: String) { currentPlayer = playerName }
    fun getMarketComponents(): List<Component> = marketComponents
    fun getMarketEngineers(): List<Engineer> = marketEngineers
    fun getMarketPilots(): List<Pilot> = marketPilots

    fun getOwnedComponents(): List<Component> = ownedComponents
    fun getAssembledCars(): List<Car> = assembledCars
    fun getHiredEngineers(): List<Engineer> = hiredEngineers
    fun getHiredPilots(): List<Pilot> = hiredPilots
    fun getJailedPilots(): List<Pilot> = jailedPilots
    fun getOpponentTeams(): List<OpponentTeam> = opponentTeams
    fun getTracks(): List<Track> = tracks
    fun getRaceHistory(): List<List<RaceResult>> = raceHistory

    fun addCar(car: Car) { assembledCars.add(car) }
    fun addComponent(component: Component) { ownedComponents.add(component) }
    fun removeComponentFromInventory(component: Component) { ownedComponents.remove(component) }
    fun removeCar(car: Car) { assembledCars.remove(car) }

    fun clearPersonnel() {
        hiredPilots.clear()
        hiredEngineers.clear()
        jailedPilots.clear()
    }

    fun clearInventory() {
        ownedComponents.clear()
        assembledCars.clear()
        hiredPilots.clear()
        hiredEngineers.clear()
        jailedPilots.clear()
        raceHistory.clear()
    }

    fun addPilotDirectly(pilot: Pilot) { hiredPilots.add(pilot) }
    fun addJailedPilotDirectly(pilot: Pilot) { jailedPilots.add(pilot) }
    fun addEngineerDirectly(engineer: Engineer) { hiredEngineers.add(engineer) }

    fun setBudget(amount: Double) {
        val currentBudget = budget.value
        currentBudget.setAmount(amount)
        budget.value = Budget().apply { setAmount(currentBudget.getAmount()) }
    }

    fun buyComponent(component: Component): Boolean {
        if (marketComponents.contains(component) && spendMoney(component.getPrice())) {
            marketComponents.remove(component)
            ownedComponents.add(component)
            return true
        }
        return false
    }

    fun hireEngineer(engineer: Engineer): Boolean {
        if (marketEngineers.contains(engineer) && spendMoney(engineer.getSalary())) {
            marketEngineers.remove(engineer)
            hiredEngineers.add(engineer)
            return true
        }
        return false
    }

    fun hirePilot(pilot: Pilot): Boolean {
        if (marketPilots.contains(pilot) && spendMoney(pilot.getSalary())) {
            marketPilots.remove(pilot)
            hiredPilots.add(pilot)
            return true
        }
        return false
    }

    fun payFine(pilot: Pilot): Boolean {
        if (pilot.hasFine() && spendMoney(pilot.getFineAmount())) {
            pilot.setFineAmount(0.0)
            pilot.setFineDeadline(0)
            return true
        }
        return false
    }

    fun releaseFromJail(pilot: Pilot): Boolean {
        val bailAmount = pilot.getSalary() * 0.5
        if (pilot.isInJail() && spendMoney(bailAmount)) {
            pilot.setJailSentence(0)
            jailedPilots.remove(pilot)
            hiredPilots.add(pilot)
            return true
        }
        return false
    }

    fun processRaceEndUpdates() {
        val toJail = mutableListOf<Pilot>()
        val fromJail = mutableListOf<Pilot>()

        hiredPilots.toList().forEach { pilot ->
            if (pilot.hasFine()) {
                pilot.setFineDeadline(pilot.getFineDeadline() - 1)
                if (pilot.getFineDeadline() <= 0) {
                    toJail.add(pilot)
                }
            }
        }

        jailedPilots.toList().forEach { pilot ->
            pilot.setJailSentence(pilot.getJailSentence() - 1)
            if (pilot.getJailSentence() <= 0) {
                fromJail.add(pilot)
            }
        }

        toJail.forEach { pilot ->
            hiredPilots.remove(pilot)
            pilot.setFineAmount(0.0)
            pilot.setJailSentence(3)
            jailedPilots.add(pilot)
        }

        fromJail.forEach { pilot ->
            jailedPilots.remove(pilot)
            hiredPilots.add(pilot)
        }
    }

    fun aiTakeComponent(component: Component) { marketComponents.remove(component) }
    fun aiTakeEngineer(engineer: Engineer) { marketEngineers.remove(engineer) }
    fun aiTakePilot(pilot: Pilot) { marketPilots.remove(pilot) }

    fun generateOpponents() {
        if (opponentTeams.isEmpty()) {
            opponentTeams.addAll(OpponentGenerator.generateOpponents(9))
        }
    }

    fun addRaceResult(results: List<RaceResult>) {
        raceHistory.add(0, results)
    }

    fun addMoney(amount: Double) {
        val currentBudget = budget.value
        currentBudget.setAmount(currentBudget.getAmount() + amount)
        budget.value = Budget().apply { setAmount(currentBudget.getAmount()) }
    }

    fun spendMoney(amount: Double): Boolean {
        if (canAfford(amount)) {
            val currentBudget = budget.value
            currentBudget.subtract(amount)
            budget.value = Budget().apply { setAmount(currentBudget.getAmount()) }
            return true
        }
        return false
    }

    fun canAfford(price: Double): Boolean = budget.value.getAmount() >= price
    }

package com.bmstu.iu3.automanagement.data

import androidx.compose.runtime.MutableState
import androidx.compose.runtime.mutableStateListOf
import androidx.compose.runtime.mutableStateOf
import com.bmstu.iu3.automanagement.models.*
import com.bmstu.iu3.automanagement.utils.MarketGenerator
import com.bmstu.iu3.automanagement.utils.OpponentGenerator

object GameState {
    private val budget: MutableState<Budget> = mutableStateOf(Budget())
    private var currentPlayer: String = ""

    private val ownedComponents = mutableStateListOf<Component>()
    private val assembledCars = mutableStateListOf<Car>()
    private val hiredEngineers = mutableStateListOf<Engineer>()
    private val hiredPilots = mutableStateListOf<Pilot>()
    private val jailedPilots = mutableStateListOf<Pilot>()
    private val opponentTeams = mutableStateListOf<OpponentTeam>()

    private val tracks = mutableStateListOf<Track>()
    private val raceHistory = mutableStateListOf<List<RaceResult>>()

    private val marketComponents = mutableStateListOf<Component>().apply {
        addAll(MarketGenerator.generateInitialMarket())
    }

    private val marketEngineers = mutableStateListOf<Engineer>().apply {
        val (engineers, _) = MarketGenerator.generateStaff()
        addAll(engineers)
    }

    private val marketPilots = mutableStateListOf<Pilot>().apply {
        val (_, pilots) = MarketGenerator.generateStaff()
        addAll(pilots)
    }

    init {
        tracks.add(Track().apply { setName("Monza"); setLength(5.79); setStraightsRatio(0.7); setCornersRatio(0.3); setElevationChange(10.0) })
        tracks.add(Track().apply { setName("Monaco"); setLength(3.33); setStraightsRatio(0.2); setCornersRatio(0.8); setElevationChange(40.0) })
        tracks.add(Track().apply { setName("Spa"); setLength(7.00); setStraightsRatio(0.5); setCornersRatio(0.5); setElevationChange(100.0) })
    }

    fun getBudgetObject() : Budget = budget.value
    fun getCurrentPlayer(): String = currentPlayer
    fun setCurrentPlayer(playerName: String) { currentPlayer = playerName }
    fun getMarketComponents(): List<Component> = marketComponents
    fun getMarketEngineers(): List<Engineer> = marketEngineers
    fun getMarketPilots(): List<Pilot> = marketPilots

    fun getOwnedComponents(): List<Component> = ownedComponents
    fun getAssembledCars(): List<Car> = assembledCars
    fun getHiredEngineers(): List<Engineer> = hiredEngineers
    fun getHiredPilots(): List<Pilot> = hiredPilots
    fun getJailedPilots(): List<Pilot> = jailedPilots
    fun getOpponentTeams(): List<OpponentTeam> = opponentTeams
    fun getTracks(): List<Track> = tracks
    fun getRaceHistory(): List<List<RaceResult>> = raceHistory

    fun addCar(car: Car) { assembledCars.add(car) }
    fun addComponent(component: Component) { ownedComponents.add(component) }
    fun removeComponentFromInventory(component: Component) { ownedComponents.remove(component) }
    fun removeCar(car: Car) { assembledCars.remove(car) }

    fun installComponentToCar(car: Car, component: Component): Boolean {
        if (!ownedComponents.contains(component)) return false

        val installed = when (component) {
            is Engine -> {
                val gearbox = car.getGearbox()
                val chassis = car.getChassis()
                if (gearbox != null && gearbox.getType() != component.getType()) return false
                if (chassis != null && component.getWeight() > chassis.getMaxEngineWeight()) return false
                car.getEngine()?.let { ownedComponents.add(it) }
                car.setEngine(component)
                true
            }
            is Gearbox -> {
                val engine = car.getEngine()
                if (engine != null && engine.getType() != component.getType()) return false
                car.getGearbox()?.let { ownedComponents.add(it) }
                car.setGearbox(component)
                true
            }
            is Chassis -> {
                val engine = car.getEngine()
                val suspension = car.getSuspension()
                if (engine != null && engine.getWeight() > component.getMaxEngineWeight()) return false
                if (suspension != null && suspension.getType() != component.getSuspensionType()) return false
                car.getChassis()?.let { ownedComponents.add(it) }
                car.setChassis(component)
                true
            }
            is Suspension -> {
                val chassis = car.getChassis()
                if (chassis != null && component.getType() != chassis.getSuspensionType()) return false
                car.getSuspension()?.let { ownedComponents.add(it) }
                car.setSuspension(component)
                true
            }
            is Aerodynamics -> {
                car.getAerodynamics()?.let { ownedComponents.add(it) }
                car.setAerodynamics(component)
                true
            }
            is Tyres -> {
                car.getTyres()?.let { ownedComponents.add(it) }
                car.setTyres(component)
                true
            }
            is MeleeWeapon -> {
                if (!canInstallWeaponByMass(car, component)) return false
                when {
                    car.getMeleeWeapon1() == null -> car.setMeleeWeapon1(component)
                    car.getMeleeWeapon2() == null -> car.setMeleeWeapon2(component)
                    else -> return false
                }
                true
            }
            is RangedWeapon -> {
                if (!canInstallWeaponByMass(car, component)) return false
                if (car.getRangedWeapon() != null) return false
                car.setRangedWeapon(component)
                true
            }
            else -> false
        }

        if (installed) {
            ownedComponents.remove(component)
            recalculateCarPerformance(car)
        }
        return installed
    }

    fun uninstallComponentFromCar(car: Car, component: Component): Boolean {
        val removed = when (component) {
            is Engine -> if (car.getEngine() == component) { car.setEngine(null); true } else false
            is Gearbox -> if (car.getGearbox() == component) { car.setGearbox(null); true } else false
            is Chassis -> if (car.getChassis() == component) { car.setChassis(null); true } else false
            is Suspension -> if (car.getSuspension() == component) { car.setSuspension(null); true } else false
            is Aerodynamics -> if (car.getAerodynamics() == component) { car.setAerodynamics(null); true } else false
            is Tyres -> if (car.getTyres() == component) { car.setTyres(null); true } else false
            is MeleeWeapon -> when {
                car.getMeleeWeapon1() == component -> { car.setMeleeWeapon1(null); true }
                car.getMeleeWeapon2() == component -> { car.setMeleeWeapon2(null); true }
                else -> false
            }
            is RangedWeapon -> if (car.getRangedWeapon() == component) { car.setRangedWeapon(null); true } else false
            else -> false
        }

        if (removed) {
            ownedComponents.add(component)
            recalculateCarPerformance(car)
        }
        return removed
    }

    fun clearPersonnel() {
        hiredPilots.clear()
        hiredEngineers.clear()
        jailedPilots.clear()
    }

    fun clearInventory() {
        ownedComponents.clear()
        assembledCars.clear()
        hiredPilots.clear()
        hiredEngineers.clear()
        jailedPilots.clear()
        raceHistory.clear()
    }

    fun addPilotDirectly(pilot: Pilot) { hiredPilots.add(pilot) }
    fun addJailedPilotDirectly(pilot: Pilot) { jailedPilots.add(pilot) }
    fun addEngineerDirectly(engineer: Engineer) { hiredEngineers.add(engineer) }

    fun setBudget(amount: Double) {
        val currentBudget = budget.value
        currentBudget.setAmount(amount)
        budget.value = Budget().apply { setAmount(currentBudget.getAmount()) }
    }

    fun buyComponent(component: Component): Boolean {
        if (marketComponents.contains(component) && spendMoney(component.getPrice())) {
            marketComponents.remove(component)
            ownedComponents.add(component)
            return true
        }
        return false
    }

    fun hireEngineer(engineer: Engineer): Boolean {
        if (marketEngineers.contains(engineer) && spendMoney(engineer.getSalary())) {
            marketEngineers.remove(engineer)
            hiredEngineers.add(engineer)
            return true
        }
        return false
    }

    fun hirePilot(pilot: Pilot): Boolean {
        if (marketPilots.contains(pilot) && spendMoney(pilot.getSalary())) {
            marketPilots.remove(pilot)
            hiredPilots.add(pilot)
            return true
        }
        return false
    }

    fun payFine(pilot: Pilot): Boolean {
        if (pilot.hasFine() && spendMoney(pilot.getFineAmount())) {
            pilot.setFineAmount(0.0)
            pilot.setFineDeadline(0)
            return true
        }
        return false
    }

    fun releaseFromJail(pilot: Pilot): Boolean {
        val bailAmount = pilot.getSalary() * 0.5
        if (pilot.isInJail() && spendMoney(bailAmount)) {
            pilot.setJailSentence(0)
            jailedPilots.remove(pilot)
            hiredPilots.add(pilot)
            return true
        }
        return false
    }

    fun processRaceEndUpdates() {
        val toJail = mutableListOf<Pilot>()
        val fromJail = mutableListOf<Pilot>()

        hiredPilots.toList().forEach { pilot ->
            if (pilot.hasFine()) {
                pilot.setFineDeadline(pilot.getFineDeadline() - 1)
                if (pilot.getFineDeadline() <= 0) {
                    toJail.add(pilot)
                }
            }
        }

        jailedPilots.toList().forEach { pilot ->
            pilot.setJailSentence(pilot.getJailSentence() - 1)
            if (pilot.getJailSentence() <= 0) {
                fromJail.add(pilot)
            }
        }

        toJail.forEach { pilot ->
            hiredPilots.remove(pilot)
            pilot.setFineAmount(0.0)
            pilot.setJailSentence(3)
            jailedPilots.add(pilot)
        }

        fromJail.forEach { pilot ->
            jailedPilots.remove(pilot)
            hiredPilots.add(pilot)
        }
    }

    fun aiTakeComponent(component: Component) { marketComponents.remove(component) }
    fun aiTakeEngineer(engineer: Engineer) { marketEngineers.remove(engineer) }
    fun aiTakePilot(pilot: Pilot) { marketPilots.remove(pilot) }

    fun generateOpponents() {
        if (opponentTeams.isEmpty()) {
            opponentTeams.addAll(OpponentGenerator.generateOpponents(9))
        }
    }

    fun addRaceResult(results: List<RaceResult>) {
        raceHistory.add(0, results)
    }

    fun addMoney(amount: Double) {
        val currentBudget = budget.value
        currentBudget.setAmount(currentBudget.getAmount() + amount)
        budget.value = Budget().apply { setAmount(currentBudget.getAmount()) }
    }

    fun spendMoney(amount: Double): Boolean {
        if (canAfford(amount)) {
            val currentBudget = budget.value
            currentBudget.subtract(amount)
            budget.value = Budget().apply { setAmount(currentBudget.getAmount()) }
            return true
        }
        return false
    }

    fun canAfford(price: Double): Boolean = budget.value.getAmount() >= price

    private fun canInstallWeaponByMass(car: Car, weapon: Weapon): Boolean {
        val chassis = car.getChassis() ?: return false
        return weapon.getWeight() <= chassis.getMaxEngineWeight()
    }

    private fun recalculateCarPerformance(car: Car) {
        car.setPerformance(car.getTotalPerformance())
    }
    }

package com.bmstu.iu3.automanagement.models

class Car {
    private var name: String = ""
    private var engine: Engine? = null
    private var gearbox: Gearbox? = null
    private var chassis: Chassis? = null
    private var suspension: Suspension? = null
    private var aerodynamics: Aerodynamics? = null
    private var tyres: Tyres? = null
    private var performance: Double = 0.0

    fun getName(): String = name
    fun setName(value: String) { name = value }

    fun getEngine(): Engine? = engine
    fun setEngine(value: Engine?) { engine = value }

    fun getGearbox(): Gearbox? = gearbox
    fun setGearbox(value: Gearbox?) { gearbox = value }

    fun getChassis(): Chassis? = chassis
    fun setChassis(value: Chassis?) { chassis = value }

    fun getSuspension(): Suspension? = suspension
    fun setSuspension(value: Suspension?) { suspension = value }

    fun getAerodynamics(): Aerodynamics? = aerodynamics
    fun setAerodynamics(value: Aerodynamics?) { aerodynamics = value }

    fun getTyres(): Tyres? = tyres
    fun setTyres(value: Tyres?) { tyres = value }

    fun getPerformance(): Double = performance
    fun setPerformance(value: Double) { performance = value }

    fun isComplete(): Boolean {
        return engine != null && gearbox != null && chassis != null && 
               suspension != null && aerodynamics != null && tyres != null
    }

    fun getTotalPerformance(): Double {
        var total = 0.0
        total += engine?.getPerformance() ?: 0.0
        total += gearbox?.getPerformance() ?: 0.0
        total += chassis?.getPerformance() ?: 0.0
        total += suspension?.getPerformance() ?: 0.0
        total += aerodynamics?.getPerformance() ?: 0.0
        total += tyres?.getPerformance() ?: 0.0
        return total
    }
}

