import com.bmstu.iu3.automanagement.ui.theme.PixelButton

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ViewCarsScreen(onBack: () -> Unit) {
    val components = GameState.getOwnedComponents()
    val cars = GameState.getAssembledCars()

    Scaffold(
        topBar = {
            TopAppBar(title = {
                Text(
                    "Your Cars",
                    fontFamily = FontFamily(Font(press_start2p))
                )
            })
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(16.dp)
        ) {
            LazyColumn(
                modifier = Modifier.weight(1f)
            ) {
                item {
                Text(
                    text = "Cars:",
                    style = MaterialTheme.typography.headlineSmall,
                    fontFamily = FontFamily(Font(press_start2p)),
                    modifier = Modifier.padding(vertical = 8.dp)
                )
            }
                if (cars.isNotEmpty()) {
                    items(cars) { car ->
                        CarCard(car)
                    }
                } else {
                    item {
                        Text(
                            text = "No cars assembled yet.",
                            style = MaterialTheme.typography.bodySmall,
                            fontFamily = FontFamily(Font(press_start2p)),
                        )
                    }
                }
            }

            Spacer(modifier = Modifier.height(16.dp))
            PixelButton(
                text = "Back to Menu",
                onClick = onBack,
                modifier = Modifier.fillMaxWidth()
            )
        }
    }
}

